// ─────────────────────────────────────────────────────────────────────────────
// Add modal — successful save
// ─────────────────────────────────────────────────────────────────────────────

describe('Upcoming Races — Add modal successful save', () => {
  const newRace = {
    id: 'new-upcoming-id',
    title: 'New Test Race',
    race_date: '2099-12-31',
    distance_m: 10000,
    location: null,
    notes: null,
    linked_activity_id: null,
    finish_time_sec: null,
    position_place: null,
    position_male: null,
    created_at: '2099-01-01T00:00:00Z',
  }

  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubRaceLog([])
    stubUpcoming([])
    visitPage()
    cy.wait('@getUpcoming')

    cy.intercept('POST', UPCOMING_EP, {
      statusCode: 201,
      body: { data: newRace, message: 'Upcoming race created' },
    }).as('createUpcoming')
  })

  it('closes modal and adds card to the section after successful save', () => {
    cy.get(`[id="${IDS.add_btn}"]`).click()
    cy.get(`[id="${IDS.form_modal}"]`).should('be.visible')

    // Fill required fields
    cy.get('#upcomingRaceTitle').type('New Test Race')

    // Pick a date via the calendar popover
    cy.get('#upcomingRaceDate').click()
    cy.get('[role="gridcell"] button:not([disabled])').last().click()

    // Select a distance preset
    cy.get(`[id="${IDS.form_modal}"]`).within(() => {
      cy.get('[role="combobox"]').first().click()
    })
    cy.get('[role="option"]').contains('10K').click()

    cy.get(`[id="${IDS.save_btn}"]`).click()
    cy.wait('@createUpcoming')

    // Modal closes on success
    cy.get(`[id="${IDS.form_modal}"]`).should('not.exist')
    // The new card should appear in the section
    cy.contains('New Test Race').should('be.visible')
  })

  it('shows server error message when POST returns 500', () => {
    cy.intercept('POST', UPCOMING_EP, {
      statusCode: 500,
      body: { error: 'Internal server error' },
    }).as('createUpcomingFail')

    cy.get(`[id="${IDS.add_btn}"]`).click()
    cy.get('#upcomingRaceTitle').type('Will Fail Race')

    cy.get('#upcomingRaceDate').click()
    cy.get('[role="gridcell"] button:not([disabled])').last().click()

    cy.get(`[id="${IDS.form_modal}"]`).within(() => {
      cy.get('[role="combobox"]').first().click()
    })
    cy.get('[role="option"]').contains('5K').click()

    cy.get(`[id="${IDS.save_btn}"]`).click()
    cy.wait('@createUpcomingFail')

    // Modal stays open on error
    cy.get(`[id="${IDS.form_modal}"]`).should('be.visible')
    cy.get(`[id="${IDS.form_modal}"]`).within(() => {
      cy.get('[role="alert"]').should('exist')
    })
  })
})

// ─────────────────────────────────────────────────────────────────────────────
// Edit modal (per-card)
// ─────────────────────────────────────────────────────────────────────────────

describe('Upcoming Races — Edit modal', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubRaceLog([])
    stubUpcoming([upcomingRace1])
    visitPage()
    cy.wait('@getUpcoming')
  })

  it('edit modal is not visible on initial load', () => {
    // Edit modal shares the same form modal ID
    cy.get(`[id="${IDS.form_modal}"]`).should('not.exist')
  })

  it('opens the edit modal with pre-filled title when pencil icon is clicked', () => {
    cy.get('[id^="upcomingRaceCard_"]')
      .first()
      .within(() => {
        cy.get('[aria-label="Edit upcoming race"]').click()
      })
    cy.get(`[id="${IDS.form_modal}"]`).should('be.visible')
    cy.contains('Edit Upcoming Race').should('be.visible')
    cy.get('#upcomingRaceTitle').should('have.value', upcomingRace1.title)
  })

  it('updates card in list and closes modal after successful PATCH', () => {
    const updatedRace = { ...upcomingRace1, title: 'Bali Marathon 2099 Updated' }
    cy.intercept('PATCH', `${UPCOMING_EP}/${upcomingRace1.id}`, {
      statusCode: 200,
      body: { data: updatedRace, message: 'Upcoming race updated' },
    }).as('patchUpcoming')

    cy.get('[id^="upcomingRaceCard_"]')
      .first()
      .within(() => {
        cy.get('[aria-label="Edit upcoming race"]').click()
      })
    cy.get(`[id="${IDS.form_modal}"]`).should('be.visible')
    cy.get('#upcomingRaceTitle').clear().type('Bali Marathon 2099 Updated')
    cy.get(`[id="${IDS.save_btn}"]`).click()
    cy.wait('@patchUpcoming')

    // Modal closes
    cy.get(`[id="${IDS.form_modal}"]`).should('not.exist')
  })

  it('shows server error inside edit modal when PATCH fails', () => {
    cy.intercept('PATCH', `${UPCOMING_EP}/${upcomingRace1.id}`, {
      statusCode: 500,
      body: { error: 'Internal server error' },
    }).as('patchFail')

    cy.get('[id^="upcomingRaceCard_"]')
      .first()
      .within(() => {
        cy.get('[aria-label="Edit upcoming race"]').click()
      })
    cy.get(`[id="${IDS.form_modal}"]`).should('be.visible')
    cy.get('#upcomingRaceTitle').clear().type('Will Fail')
    cy.get(`[id="${IDS.save_btn}"]`).click()
    cy.wait('@patchFail')

    // Modal stays open on error
    cy.get(`[id="${IDS.form_modal}"]`).should('be.visible')
    cy.get(`[id="${IDS.form_modal}"]`).within(() => {
      cy.get('[role="alert"]').should('exist')
    })
  })
})

