// Delete confirmation dialog (per-card)
// ─────────────────────────────────────────────────────────────────────────────

describe('Upcoming Races — Delete confirmation dialog', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubRaceLog([])
    stubUpcoming([upcomingRace1])
    visitPage()
    cy.wait('@getUpcoming')
  })

  it('opens the delete confirmation dialog when trash icon is clicked', () => {
    cy.get(`[id="${IDS.delete_btn}"]`).first().click()
    cy.contains('Delete upcoming race?').should('be.visible')
  })

  it('shows the race title in the confirmation dialog', () => {
    cy.get(`[id="${IDS.delete_btn}"]`).first().click()
    cy.get('[role="dialog"]').should('be.visible').and('contain.text', upcomingRace1.title)
  })

  it('closes the dialog without deleting when Cancel is clicked', () => {
    cy.get(`[id="${IDS.delete_btn}"]`).first().click()
    cy.contains('Delete upcoming race?').should('be.visible')
    cy.contains('button', 'Cancel').click()
    cy.contains('Delete upcoming race?').should('not.exist')
    // Card is still present
    cy.get('[id^="upcomingRaceCard_"]').should('have.length', 1)
  })

  it('removes the card from the list after confirming delete', () => {
    cy.intercept('DELETE', `${UPCOMING_EP}/${upcomingRace1.id}`, {
      statusCode: 200,
      body: { message: 'Deleted' },
    }).as('deleteUpcoming')

    cy.get(`[id="${IDS.delete_btn}"]`).first().click()
    cy.get(`[id="${IDS.delete_confirm_btn}"]`).click()
    cy.wait('@deleteUpcoming')

    // Card is removed and empty state appears
    cy.get('[id^="upcomingRaceCard_"]').should('not.exist')
    cy.get(`[id="${IDS.empty_state}"]`).should('be.visible')
  })
})

